import Link from 'next/link';
import { getServerSession } from 'next-auth';

export default async function Navbar() {
  const session = await getServerSession();

  return (
    <nav className="bg-white shadow-md p-4">
      <div className="container mx-auto flex justify-between items-center">
        <Link href="/" className="text-xl font-bold text-blue-600">
          RestoManager
        </Link>
        <div className="space-x-4">
          <Link href="/restaurants" className="text-gray-700 hover:text-blue-600">
            Restaurants
          </Link>
          {session ? (
            <>
              <Link href="/orders" className="text-gray-700 hover:text-blue-600">
                Orders
              </Link>
              <Link href="/api/auth/signout" className="text-gray-700 hover:text-blue-600">
                Sign Out
              </Link>
            </>
          ) : (
            <Link href="/api/auth/signin" className="text-gray-700 hover:text-blue-600">
              Sign In
            </Link>
          )}
        </div>
      </div>
    </nav>
  );
}
